svg.script:
const ring = document.getElementById('rainbowRing');
const cloudWrap = document.getElementById('cloudWrap');
const halo = document.getElementById('halo');
const runnerAura = document.getElementById('runnerAura');
const runnerTail = document.getElementById('runnerTail');
const runnerCore = document.getElementById('runnerCore');
const ringLayers = [
  { el: document.getElementById('r1'), opacity: 1 },
  { el: document.getElementById('r2'), opacity: .98 },
  { el: document.getElementById('r3'), opacity: .96 },
  { el: document.getElementById('r4'), opacity: .92 },
];
const capsule = document.getElementById('capsuleEye');
const arcEye = document.getElementById('arcEye');
const arcL = document.getElementById('arcL');
const arcR = document.getElementById('arcR');
const sparkEls = [...document.querySelectorAll('.spark')];
const phaseTag = document.getElementById('phaseTag');
const timelineFill = document.getElementById('timelineFill');
const pauseBtn = document.getElementById('pause');
const replayBtn = document.getElementById('replay');
const light = document.getElementById('light');
const debug = document.getElementById('debug');

const TOTAL = 2.84;
const GAP = .82;
const SWEEP_OFFSET = -16;
const RING_COUNT = 4;
const SMILE = { h: 1, w: 3.5 };
const LAUGH = { h: 1.32, w: 3.95 };
const EYE_CY = 12.7;
const CX_L = 8.65;
const CX_R = 15.35;
const sparks = [
  { x: 4.1, y: 4.1, dx: -2.4, dy: -1.7, d: 0, s: 1.1, rot: -18 },
  { x: 12.1, y: 1.2, dx: .1, dy: -2.4, d: .08, s: .95, rot: 16 },
  { x: 20.6, y: 6.4, dx: 2.2, dy: -1.4, d: .14, s: 1, rot: 24 },
  { x: 22.1, y: 15.4, dx: 2.2, dy: 1.4, d: .2, s: .92, rot: -14 },
  { x: 10.3, y: 22, dx: -.6, dy: 2.1, d: .25, s: .85, rot: 11 },
  { x: 1.8, y: 14.2, dx: -2, dy: .9, d: .18, s: .82, rot: -28 },
];

let elapsed = 0;
let prev = 0;
let paused = false;

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }
function lerp(a, b, t) { return a + (b - a) * t; }
function easeOutCubic(x) { return 1 - Math.pow(1 - x, 3); }
function easeInCubic(x) { return x * x * x; }
function easeInOutCubic(x) {
  return x < .5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2;
}
function arcPath(h, w) {
  const w2 = w / 2;
  const peakY = EYE_CY - 2 * h;
  return {
    l: `M ${(CX_L - w2).toFixed(2)} ${EYE_CY} Q ${CX_L} ${peakY.toFixed(2)} ${(CX_L + w2).toFixed(2)} ${EYE_CY}`,
    r: `M ${(CX_R - w2).toFixed(2)} ${EYE_CY} Q ${CX_R} ${peakY.toFixed(2)} ${(CX_R + w2).toFixed(2)} ${EYE_CY}`,
  };
}
function setArc(shape) {
  const d = arcPath(shape.h, shape.w);
  arcL.setAttribute('d', d.l);
  arcR.setAttribute('d', d.r);
}
function setCenteredTransform(el, sx, sy = sx, rot = 0, tx = 0, ty = 0) {
  el.setAttribute('transform', `translate(${(12 + tx).toFixed(3)} ${(12 + ty).toFixed(3)}) rotate(${rot.toFixed(3)}) scale(${sx.toFixed(4)} ${sy.toFixed(4)}) translate(-12 -12)`);
}
function setRing(layerLevels, haloOpacity, scale, runnerProgress, runnerOpacity) {
  ringLayers.forEach(({ el, opacity: layerOpacity }, i) => {
    el.setAttribute('stroke-dasharray', '100 .01');
    el.setAttribute('stroke-dashoffset', 0);
    el.setAttribute('stroke-opacity', (clamp(layerLevels[i] || 0, 0, 1) * layerOpacity).toFixed(3));
  });
  halo.setAttribute('stroke-dasharray', '100 .01');
  halo.setAttribute('stroke-dashoffset', 0);
  halo.setAttribute('stroke-opacity', clamp(haloOpacity, 0, .1).toFixed(3));
  const runnerOffset = SWEEP_OFFSET - 100 * runnerProgress;
  runnerAura.setAttribute('stroke-dashoffset', runnerOffset.toFixed(2));
  runnerTail.setAttribute('stroke-dashoffset', runnerOffset.toFixed(2));
  runnerCore.setAttribute('stroke-dashoffset', runnerOffset.toFixed(2));
  runnerAura.setAttribute('stroke-opacity', (runnerOpacity * .18).toFixed(3));
  runnerTail.setAttribute('stroke-opacity', (runnerOpacity * .78).toFixed(3));
  runnerCore.setAttribute('stroke-opacity', runnerOpacity.toFixed(3));
  setCenteredTransform(ring, scale);
}
function setSparkles(amount) {
  sparkEls.forEach((el, i) => {
    const cfg = sparks[i];
    const p = clamp((amount - cfg.d) / .62, 0, 1);
    const visible = Math.sin(Math.PI * p);
    const move = easeOutCubic(p);
    const x = cfg.x + cfg.dx * move;
    const y = cfg.y + cfg.dy * move;
    const scale = cfg.s * (.45 + .75 * visible);
    el.setAttribute('transform', `translate(${x.toFixed(2)} ${y.toFixed(2)}) rotate(${(cfg.rot + 80 * p).toFixed(1)}) scale(${scale.toFixed(3)})`);
    el.setAttribute('opacity', (visible * .95).toFixed(3));
  });
}
function render(t) {
  const T_anti = .16;
  const T_layers = .96;
  const T_confirm = .18;
  const T_hold = .86;
  const T_fade = .42;
  const T_back = .26;
  const a1 = T_anti;
  const a2 = a1 + T_layers;
  const a3 = a2 + T_confirm;
  const a4 = a3 + T_hold;
  const a5 = a4 + T_fade;
  const a6 = a5 + T_back;

  let phase = 'idle baseline';
  let layerLevels = [0, 0, 0, 0];
  let haloOpacity = 0;
  let ringScale = 1;
  let runnerProgress = 0;
  let runnerOpacity = 0;
  let cloudSx = 1;
  let cloudSy = 1;
  let cloudRot = 0;
  let capsuleOp = 1;
  let arcOp = 0;
  let eye = SMILE;
  let sparkleAmount = 0;

  if (t < a1) {
    phase = '① squash charge';
    const p = t / T_anti;
    const pulse = Math.sin(Math.PI * p);
    cloudSx = 1 + .055 * pulse;
    cloudSy = 1 - .08 * pulse;
    capsuleOp = 1;
    arcOp = 0;
    eye = SMILE;
  } else if (t < a2) {
    const p = (t - a1) / T_layers;
    const laps = p * RING_COUNT;
    const completed = Math.min(RING_COUNT, Math.floor(laps));
    const lapLocal = laps - completed;
    const lightIn = easeOutCubic(clamp(p * 4, 0, 1));
    const justLit = completed > 0 ? Math.max(0, 1 - (lapLocal * T_layers / RING_COUNT) / .085) : 0;
    phase = `② runner lap ${Math.min(completed + 1, RING_COUNT)}/${RING_COUNT}`;
    layerLevels = ringLayers.map((_, i) => i < completed ? 1 : 0);
    haloOpacity = 0;
    ringScale = 1 + .014 * lightIn + .012 * justLit;
    runnerProgress = laps;
    runnerOpacity = .9 * lightIn;
    cloudSx = cloudSy = 1 + .014 * lightIn + .007 * justLit;
    capsuleOp = 1 - easeOutCubic(clamp(p * 1.7, 0, 1));
    arcOp = easeOutCubic(clamp(p * 1.7, 0, 1));
    eye = {
      h: lerp(SMILE.h, LAUGH.h, easeInOutCubic(clamp((p - .2) / .8, 0, 1))),
      w: lerp(SMILE.w, LAUGH.w, easeInOutCubic(clamp((p - .2) / .8, 0, 1))),
    };
  } else if (t < a3) {
    phase = '③ confirm lap';
    const p = (t - a2) / T_confirm;
    const pop = Math.sin(Math.PI * p);
    layerLevels = [1, 1, 1, 1];
    haloOpacity = .04;
    ringScale = 1.018 + .02 * pop;
    runnerProgress = RING_COUNT + p;
    runnerOpacity = .95 * (1 - .25 * p);
    cloudSx = cloudSy = 1.02 + .018 * pop;
    cloudRot = 2.6 * Math.sin(2 * Math.PI * p);
    capsuleOp = 0;
    arcOp = 1;
    eye = LAUGH;
    sparkleAmount = p * .72;
  } else if (t < a4) {
    phase = '④ happy hold';
    const p = (t - a3) / T_hold;
    layerLevels = [1, 1, 1, 1];
    haloOpacity = .04;
    ringScale = 1.026 + .006 * Math.sin(2 * Math.PI * p);
    runnerProgress = RING_COUNT + 1;
    runnerOpacity = 0;
    cloudSx = cloudSy = 1.025;
    capsuleOp = 0;
    arcOp = 1;
    eye = LAUGH;
    sparkleAmount = .75 + p * .45;
  } else if (t < a5) {
    phase = '⑤ soft fade';
    const p = (t - a4) / T_fade;
    const keep = 1 - easeInCubic(p);
    layerLevels = [1, 1, 1, 1].map(() => .12 + .88 * keep);
    haloOpacity = .04 * keep;
    ringScale = 1.006 + .02 * keep;
    runnerProgress = RING_COUNT + 1;
    runnerOpacity = 0;
    cloudSx = cloudSy = 1 + .025 * keep;
    capsuleOp = 0;
    arcOp = 1;
    eye = {
      h: lerp(LAUGH.h, SMILE.h, easeInOutCubic(p)),
      w: lerp(LAUGH.w, SMILE.w, easeInOutCubic(p)),
    };
    sparkleAmount = 1.2;
  } else if (t < a6) {
    phase = '⑥ smile return';
    const p = (t - a5) / T_back;
    const out = 1 - easeOutCubic(p);
    layerLevels = [1, 1, 1, 1].map(() => .12 * out);
    haloOpacity = .02 * out;
    ringScale = 1 + .02 * out;
    runnerProgress = RING_COUNT + 1;
    runnerOpacity = 0;
    capsuleOp = easeInOutCubic(p);
    arcOp = 1 - easeInOutCubic(p);
    eye = SMILE;
  } else {
    phase = 'idle baseline';
  }

  setCenteredTransform(cloudWrap, cloudSx, cloudSy, cloudRot);
  setRing(layerLevels, haloOpacity, ringScale, runnerProgress, runnerOpacity);
  setSparkles(sparkleAmount);
  capsule.setAttribute('opacity', capsuleOp.toFixed(3));
  arcEye.setAttribute('opacity', arcOp.toFixed(3));
  setArc(eye);
  phaseTag.textContent = phase;
  timelineFill.style.width = `${clamp((t / TOTAL) * 100, 0, 100).toFixed(1)}%`;
}
function loop(now) {
  if (!prev) prev = now;
  const dt = (now - prev) / 1000;
  prev = now;
  if (!paused) elapsed += dt;
  const cycle = TOTAL + GAP;
  const tt = elapsed % cycle;
  render(tt > TOTAL ? 0 : tt);
  requestAnimationFrame(loop);
}

setArc(SMILE);
setSparkles(0);
requestAnimationFrame(loop);
